function sunLong(jd){
  const T=(jd-2451545.0)/36525.0;
  const L0=280.46646+36000.76983*T+0.0003032*T*T;
  const Mr=(357.52911+35999.05029*T-0.0001537*T*T)*R;
  const C=(1.9146-0.004817*T)*Math.sin(Mr)+0.019993*Math.sin(2*Mr)+0.00029*Math.sin(3*Mr);
  return((L0+C)%360+360)%360;
}
function jdFull(y,m,d,h){return jd0(y,m,d)+(h||0)/24;}
function findSRjd(nSDeg,eY,bm,bd){
  let lo=jdFull(eY,bm,bd,0)-1.5,hi=jdFull(eY,bm,bd,0)+1.5;
  for(let i=0;i<25;i++){
    const mid=(lo+hi)/2;
    let diff=sunLong(mid)-nSDeg;
    if(diff>180)diff-=360;if(diff<-180)diff+=360;
    if(diff>0)hi=mid;else lo=mid;
  }
  return(lo+hi)/2;
}
function calcASCjd(jd){
  const T=(jd-2451545.0)/36525.0;
  let gmst=280.46061837+360.98564736629*(jd-2451545.0)+0.000387933*T*T;
  gmst=((gmst%360)+360)%360;
  const lst=((gmst+lon)%360+360)%360;
  const eps=(23.4393-0.013*T)*R;const A=lst*R,L=lat*R;
  return((Math.atan2(-Math.cos(A),Math.sin(A)*Math.cos(eps)+Math.tan(L)*Math.sin(eps))/R+180)%360+360)%360;
}
function calcMCjd(jd){
  const T=(jd-2451545.0)/36525.0;
  let gmst=280.46061837+360.98564736629*(jd-2451545.0)+0.000387933*T*T;
  gmst=((gmst%360)+360)%360;
  const lst=((gmst+lon)%360+360)%360;
  const eps=(23.4393-0.013*T)*R;const A=lst*R;
  return((Math.atan2(Math.sin(A),Math.cos(A)*Math.cos(eps))/R)%360+360)%360;
}

