    let closest=data[0],minDist=999;
    for(const d of data){const dd=toDecDate(d.date);if(Math.abs(dd-evtDec)<minDist){minDist=Math.abs(dd-evtDec);closest=d;}}
    if(!closest?.planetes)continue;
