        if(!pp[pn])continue;
        const asp=bestAspect(pp[pn].longitude_absolue,slotAsc,1.0);
        if(asp){
          const key='p'+pn+'_'+asp.name+'_nASC';
          const dup=seen.has(key);if(!dup)seen.add(key);
          const tight=1-asp.ao/asp.ou;
          const w=Math.round(asp.weight*pw(pn)*ps(pn)*tight*(dup?0.25:1)*10)/10;
          if(w>=0.3){score+=w;details.push(evt.label+': p'+pn+' '+asp.name+' nASC ('+w.toFixed(1)+' '+asp.ao.toFixed(2)+'\u00B0'+(dup?'*':'')+')');
          }
        }
      }
