          const key='pASC_'+asp.name+'_n'+np.name;
          const dup=seen.has(key);if(!dup)seen.add(key);
          const tight=1-asp.ao/asp.ou;
          const w=Math.round(asp.weight*pw(np.name)*1.5*tight*(dup?0.25:1)*10)/10;
          if(w>=0.3){score+=w;details.push(evt.label+': pASC '+asp.name+' n'+np.name+' ('+w.toFixed(1)+' '+asp.ao.toFixed(2)+'\u00B0'+(dup?'*':'')+')');
          }
        }
      }
