  }).join('');
  html+='</table>';
}

html+='<p style="font-size:10px;color:'+(gridFull?'#888':'#a60')+';margin-top:16px;line-height:1.4"><b>Couverture</b> : '+nAnalysed+' créneau(x) avec ASC dans ce rapport ; '+scorerItems.length+' item(s) Scorer.'+scanMetaNote+(gridFull?'':' — <b>scan partiel</b> : seuls les signes présents dans ces créneaux apparaissent en table ; le « Pic par signe » compare les totaux <em>uniquement</em> sur cet ensemble (pas sur 288 pas de 5 min).')+'</p>';
